char nextGreatestLetter(char* letters, int n, char target) {
    int lo = 0, hi = n;
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (letters[mid] <= target) lo = mid + 1;
        else hi = mid;
    }
    return lo == n ? letters[0] : letters[lo];
}
